<body>
  <div class="status-bar-data-container">$1</div>
  <div class="status-bar-container">
    <div class="status-bar-header">修仙系统</div>
    <div class="status-bar-tabs">
      <!-- 选项卡按钮将在此生成 -->
    </div>
    <div class="status-bar-content">
      <!-- 内容区块将在此生成 -->
      <div class="no-data active">正在加载数据...</div>
    </div>
  </div>

  <script>
  document.addEventListener('DOMContentLoaded', () => {
    const dataContainer = document.querySelector('.status-bar-data-container');
    const contentArea = document.querySelector('.status-bar-content');
    const tabsContainer = document.querySelector('.status-bar-tabs');
    const header = document.querySelector('.status-bar-header');
    const root = document.documentElement; // Get root element for CSS variables

    if (!dataContainer || !contentArea || !tabsContainer) return;

    function parseData(text) {
      const data = {};
      const configMatch = text.match(/config:\s*([\s\S]*?)(?=\n\[|\n\/\/|\[修仙系统 END\])/);
      if (configMatch) {
          data.config = {};
          const configLines = configMatch[1].trim().split('\n');
          configLines.forEach(line => {
              const parts = line.split(':');
              if (parts.length === 2) {
                  data.config[parts[0].trim()] = parts[1].trim();
              }
          });
      }

      const blockRegex = /\[([\u4e00-\u9fa5\w]+)\]([\s\S]*?)\[\/\1\]/g; // Match Chinese and English names
      let match;
      data.blocks = [];
      while ((match = blockRegex.exec(text)) !== null) {
        const blockName = match[1];
        const blockContent = match[2].trim();
        const items = {};
        const lines = blockContent.split('\n');
        let currentKey = null;
        let currentValue = '';
        let currentItemList = null; // To handle list items like '物品列表'

        lines.forEach(line => {
          line = line.trim(); // trim each line
          // if (line === '') return; // Don't skip empty lines, they might be part of multiline values

          const listItemMatch = line.match(/^\s*-\s*名称:\s*(.*)/); // Check for '- 名称: ' pattern
          const itemDetailMatch = line.match(/^\s*(描述|数量):\s*(.*)/); // Check for item details within list

          if (listItemMatch) {
               // If we were processing a previous item list, push it now
               if (currentItemList !== null) {
                   if(currentKey !== null) items[currentKey] = currentItemList;
               } else if (currentKey !== null) {
                   // If we were processing a standard key, push it
                   items[currentKey] = currentValue.trim();
               }
               // Start a new list item
               const itemName = listItemMatch[1].trim();
               currentItemList = currentItemList || []; // Initialize if null
               currentItemList.push({ '名称': itemName });
               currentKey = '物品列表'; // This applies to the entire list
               currentValue = ''; // Reset currentValue for standard keys

           } else if (itemDetailMatch && currentItemList !== null && currentItemList.length > 0) {
               // Add details to the last item in the current list
               const detailKey = itemDetailMatch[1].trim();
               const detailValue = itemDetailMatch[2].trim();
               currentItemList[currentItemList.length - 1][detailKey] = detailValue;
               currentValue = ''; // Still part of list item, no standard value

           } else { // Standard key: value lines outside of lists
             // If we were processing an item list, push it before handling a standard key
             if (currentItemList !== null) {
                 if(currentKey !== null) items[currentKey] = currentItemList;
                 currentItemList = null; // Reset list handler
                 currentKey = null; // Reset key handler
             }

             const parts = line.match(/^([^:]+):\s*(.*)/);
             if (parts) {
               if (currentKey !== null) items[currentKey] = currentValue.trim();
               currentKey = parts[1].trim();
               currentValue = parts[2].trim();
             } else if (currentKey !== null) {
               // Handle multiline values for standard key-value
               currentValue += '\\n' + line;
             }
           }
        });

        // Process any remaining item list or current key-value pair at the end of the block
        if (currentItemList !== null && currentItemList.length > 0) {
            if(currentKey !== null) items[currentKey] = currentItemList;
        } else if (currentKey !== null) {
             items[currentKey] = currentValue.trim();
        }

        data.blocks.push({ name: blockName, items: items });
      }
      return data;
    }


    function applyThemeAndSettings(config) {
      if (!config) return;

      // Apply Theme
      if (config.theme === 'fantasy') {
         header.textContent = "修仙系统"; // 标题与主题一致
      }
       // 计算RGB用于阴影
      const primaryColor = root.style.getPropertyValue('--primary-color').trim();
      const rgbMatch = primaryColor.match(/^#?([a-f\d]{2})([a-f\d]{2})([a-f\d]{2})$/i);
      if (rgbMatch) {
          const rgb = parseInt(rgbMatch[1], 16) + ',' + parseInt(rgbMatch[2], 16) + ',' + parseInt(rgbMatch[3], 16);
          root.style.setProperty('--primary-color-rgb', rgb);
      }

      // Apply Settings (Font Size and Window Scale)
      // Ensure values are parsed as numbers
      const fontScale = parseFloat(config.font_size) || 1.0;
      const windowScale = parseFloat(config.window_scale) || 1.0;

      root.style.setProperty('--font-scale', fontScale);
      root.style.setProperty('--window-scale', windowScale);
      // The actual CSS variables handle the resizing
    }

    function renderData(data) {
      contentArea.innerHTML = ''; // Clear previous content
      tabsContainer.innerHTML = ''; // Clear previous tabs

      if (!data.blocks || data.blocks.length === 0) {
        contentArea.innerHTML = '<div class="no-data active">数据加载失败或不存在。</div>';
        return;
      }

      data.blocks.forEach((block, index) => {
        // Create Tab Button
        const tabButton = document.createElement('button');
        tabButton.textContent = block.name;
        tabButton.setAttribute('data-block', block.name);
        tabsContainer.appendChild(tabButton);

        // Create Content Block
        const blockDiv = document.createElement('div');
        blockDiv.className = 'data-block';
        blockDiv.setAttribute('data-block', block.name); // Link block to tab

        let itemsHTML = `<div class="data-block-title">${block.name}</div>`;

        for (const key in block.items) {
            const value = block.items[key];

            if (key === '物品列表' && Array.isArray(value)) {
                // Handle item lists (like '物品列表') specifically for the backpack block
                 itemsHTML += `<div class="data-item items-list-container">`; // Add a container class for the list itself
                  // The list title "物品列表" is added here
                  itemsHTML += `<div class="data-item list-title-item"><span class="data-key">${key.replace('\\n', '<br>')}:</span></div>`; // Display list title

                 if (value.length > 0) {
                    value.forEach(item => {
                       // Check if item is an empty slot placeholder
                       const isEmptySlot = item.名称.includes('空位');
                       const itemClassName = isEmptySlot ? 'data-item empty-slot' : 'data-item actual-item'; // Differentiate actual items and empty slots

                       itemsHTML += `<div class="${itemClassName}">
                                        <span class="data-key">${item.名称.replace('\\n', '<br>')}</span>`;

                       // Render description if available
                       if (item.描述) {
                              itemsHTML += `<span class="data-value">${item.描述.replace('\\n', '<br>')}</span>`; // Display description directly
                       }
                        // Add Quantity if available
                         if (item.数量) {
                             itemsHTML += `<span class="data-value quantity">数量: ${item.数量.replace('\\n', '<br>')}</span>`;
                         }

                        itemsHTML += `</div>`; // End individual item div
                    });
                 } else {
                     // Display message if backpack list is empty
                      itemsHTML += `<div class="data-item empty-slot"><span class="data-value">背包空空如也。</span></div>`;
                 }
                 itemsHTML += `</div>`; // End items-list-container

            } else {
                // Handle standard key-value pairs
                // Currency line should be in the Backpack block
                 const itemClass = (key.includes('货币') && block.name === '背包') ? 'data-item currency-line' : 'data-item';

                itemsHTML += `
                <div class="${itemClass}">
                  <span class="data-key">${key.replace('\\n', '<br>')}</span>
                  <span class="data-value">${value.replace('\\n', '<br>')}</span>
                </div>`;
            }
        }

        blockDiv.innerHTML = itemsHTML;
        contentArea.appendChild(blockDiv);

        // Activate first tab and block by default
        if (index === 0) {
          tabButton.classList.add('active');
          blockDiv.classList.add('active');
        }
      });

      // Add tab switching functionality
      tabsContainer.querySelectorAll('button').forEach(button => {
        button.addEventListener('click', (event) => {
          const targetBlockName = event.target.getAttribute('data-block');

          // Deactivate all tabs and blocks
          tabsContainer.querySelectorAll('button').forEach(btn => btn.classList.remove('active'));
          contentArea.querySelectorAll('.data-block').forEach(blockDiv => blockDiv.classList.remove('active'));

          // Activate clicked tab and corresponding block
          event.target.classList.add('active');
          contentArea.querySelectorAll(`.data-block[data-block="${targetBlockName}"]`).forEach(blockDiv => blockDiv.classList.add('active'));
        });
      });
    }

    const rawData = dataContainer.textContent.trim();
    if (rawData) {
      const parsedData = parseData(rawData);
      applyThemeAndSettings(parsedData.config);
      renderData(parsedData);
    } else {
         contentArea.innerHTML = '<div class="no-data active">未能从数据容器加载原始数据。</div>';
    }
  });
  </script>
</body>
</html>
